      /* <flatten type="Javascript"> */
function show$GridVoucherDetail$(g) {
  var f = g.get_element().parentForm, tagIdx = g._getColumnOrder('tag') - 1;
  if (f._callFromOther) {
    g._siftColumnIndex = tagIdx;
  } else {
    g._fields[tagIdx].Visible = false;
    hiddenToolbarButton(g, ['GenerateInvoice']);
  }
}
function load$GridVoucherDetail$(g) {
  g.add_itemValueChanged(onChange$GridVoucherDetail$);
  g.add_onResponseComplete(on$GridVoucherDetail$ResponseComplete);
  g.add_commandEvent(on$GridVoucherDetail$ExecuteCommand);
  g.$a = {
    tt_nt: '[tt_qd]:=[tt_nt]',
    tt: '[tt_qd]:=[tt]',
    tt_qd: '[tt_qd]:=[ty_gia_hd]==0?[tt]:[tt]/[ty_gia_hd]',
    tt_tg: '[tt]:=[tt_nt]*[ty_gia]'
  };
  g.$h = [['voucherCode', 'String', g._voucherCode], 'ma_kh', 'ngay_lct', 'ma_dvcs', 'stt_rec'];
  udf$Detail$(g);
}
function dispose$GridVoucherDetail$(g) {
  g.$a = null;
  try {g.remove_commandEvent(on$GridVoucherDetail$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridVoucherDetail$ResponseComplete);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$GridVoucherDetail$);} catch (ex) {}
}

function onChange$GridVoucherDetail$VoucherNumber(o) {o.grid.request(o, 'VoucherNumber', 'VoucherNumber', ['so_phieu', 'stt_rec_phieu'], o.grid.$h, true);}
function onChange$GridVoucherDetail$InvoiceNumber(o) {o.grid.request(o, 'InvoiceNumber', 'InvoiceNumber', ['so_hd', 'stt_rec_hd'], o.grid.$h, true);}
function onChange$GridVoucherDetail$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'tt_nt':
      g.validExpression(o, [g.$a.tt_tg], null, null);
      set$GridVoucherDetail$Payment(o, g, f);
      checkTag(o);
      g.live(o, 'tt_qd');
      break;
    case 'tt_qd': case 'tt':
      checkTag(o);
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  switch (action) {
    case 'ImportData':
      if (f._action == 'View') break;
      if (!f.validFields('ma_kh, ngay_lct')) break;
      g.showForm('RDDetailImport');
      break;
    case 'Download':
      request$Download(g, action);
      break;
    case 'GenerateInvoice':
      if (f._action == 'View') break;
      if (f._callFromOther) {
        g.request(g, 'GenerateInvoice', 'GenerateInvoice', [], [['ext_key', 'String', f._extKey], ['action', 'String', f._action], 'stt_rec']);
      }
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm, r;
  switch (context) {
    case 'VoucherNumber':
      r = g._getItemValue(o.row, g._getColumnOrder('ty_gia'));
      g.setItemGridBehavior(o, [
        ['tk', result[0].Value, null, true],
        ['ngay_phieu', result[1].Value, null, true],
        ['tien_nt', result[2].Value, null, true],
        ['ma_nt', result[3].Value, null, true],
        ['ty_gia', result[4].Value, null, true],
        ['ma_kh_phieu', result[5].Value, null, true],
        ['tien_cl_nt', result[6].Value, null, true]
      ]);
      if (r != result[4].Value) g.validExpression(o, [g.$a.tt_tg], null, null);
      set$GridVoucherDetail$Payment(o, g, f);
      g.live(o, 'so_hd');
      break;
    case 'InvoiceNumber':
      r = g._getItemValue(o.row, g._getColumnOrder('ty_gia_hd'));
      g.setItemGridBehavior(o, [
        ['tk_du', result[0].Value, null, false],
        ['ngay_hd', result[1].Value, null, false],
        ['ma_nt_hd', result[2].Value, null, false],
        ['ty_gia_hd', result[3].Value, null, false],
        ['so_lsx', result[4].Value, null, false],
        ['ma_vv', result[5].Value, null, false],
        ['ma_sp', result[6].Value, null, false],
        ['ma_bp', result[7].Value, null, false],
        ['ma_hd', result[8].Value, null, false],
        ['ma_ku', result[9].Value, null, false],
        ['ma_phi', result[10].Value, null, false],
        ['tien_hd_nt', result[11].Value, null, false],
        ['da_tt_nt', result[12].Value, null, false],
        ['cl_nt', result[13].Value, null, false],
        ['ma_kh_hd', result[14].Value, null, false]
      ]);
      if (r != result[3].Value) g.validExpression(o, [g.$a.tt_tg], null, null);
      set$GridVoucherDetail$Payment(o, g, f);
      g.live(o, 'tt_nt');
      break;
    case 'Download':
      g._key = result[0].Value;
      break;
    case 'GenerateInvoice':
      generateInvoice(g, result);
      break;
    default:
      break;
  }
}

function set$GridVoucherDetail$Payment(o, g, f) {
  var c = g._getItemValue(o.row, g._getColumnOrder('ma_nt')), v = g._getItemValue(o.row, g._getColumnOrder('ma_nt_hd'));
  if (c == v) g.executeExpression(o, [g.$a.tt_nt]);
    else {
      if (v == f._baseCurrency) g.executeExpression(o, [g.$a.tt]);
        else g.executeExpression(o, [g.$a.tt_qd]);
    }
}
function onFocus$GridVoucherDetail$InvoiceNumber(o) {
  var g = $find(o.id.split('_inputCell_')[0]);
  g._enter(o);
  var f = g.get_element().parentForm;
  if (f._action == 'New' || f._action == 'Edit') o._controlBehavior.add_loading(on$Filter$Before$Loading);
}
function on$Filter$Before$Loading(sender, e) {
  var g = sender._element.grid, f = g.get_element().parentForm;
  a = [
    {Name: 'ma_dvcs', Type: 'String', Value: f.getItemValue('ma_dvcs')},
    {Name: 'stt_rec', Type: 'String', Value: f.getItemValue('stt_rec')},
    {Name: 'ma_kh', Type: 'String', Value: f.getItemValue('ma_kh')},
    {Name: 'ngay_lct', Type: 'DateTime', Value: f.getItemValue('ngay_lct')}
  ];
  sender.set_memvars(a);
}

function onChange$SelectedRow(o) {
  var a = o.id.split('_inputCell_'), g = o.grid, f = g.get_element().parentForm;
  if (!g) g = $find(a[0]);
  var r = g._activeRow, ctag = g._getColumnOrder('tag'), k1 = g._getColumnOrder('tt_nt'), k2 = g._getColumnOrder('tt_qd'), k3 = g._getColumnOrder('tt'), k4 = g._getColumnOrder('tt_nt0');

  if (g._getItemValue(r, ctag)) {
    var cVoucher = g._getColumnOrder('stt_rec_phieu'), pt_rec = g._getItemValue(r, cVoucher), tien_cl_nt = g._getItemValue(r, g._getColumnOrder('tien_cl_nt'));
    var cl_nt = g._getItemValue(r, g._getColumnOrder('cl_nt'));
    var t_pb_nt = 0, t_pb_nt0 = 0;

    for (var i = 1; i <= g._rowCount; i++) {
      if (g._getItemValue(i, cVoucher) == pt_rec) {
        t_pb_nt0 += g._getItemValue(i, k4);
        if (g._getItemValue(i, ctag) && i != r) {
          t_pb_nt += g._getItemValue(i, k1);
        }
      }
    }

    var pb_tg = t_pb_nt0 - t_pb_nt;
    if (tien_cl_nt + pb_tg > 0) {
      g._setItemValue(r, k1, Math.min(cl_nt, tien_cl_nt + pb_tg));
      g.validExpression(o, [g.$a.tt_tg], null, null);
      set$GridVoucherDetail$Payment(o, g, f);
    }
  } else {
    g._setItemValue(r, k1, 0);
    g._setItemValue(r, k2, 0);
    g._setItemValue(r, k3, 0);
  }
}
function checkTag(o){
  var g = o.grid, f = g.get_element().parentForm;
  if (f._callFromOther) {
    var r = g._activeRow, l1 = g._getColumnOrder('tt_nt'), l2 = g._getColumnOrder('tt_qd'), l3 = g._getColumnOrder('tt'), ctag = g._getColumnOrder('tag');
    var v = (g._getItemValue(r, l1) != 0 || g._getItemValue(r, l2) != 0 || g._getItemValue(r, l3) != 0);
    g._setItemValue(r, ctag, v);
  }
}

function hiddenToolbarButton(g, a) {
  for (var i = 0; i < a.length; i += 1) {
    for (var j = g._toolbar.length - 1; j >= 0; j--) {
      if (g._toolbar[j][0] == a[i]) Array.removeAt(g._toolbar, j);
    }
  }
}

function generateInvoice(g, a) {
  if (a.length <= 0) return;

  var f = g.get_element().parentForm, pg = f.grid._parentGrid, first = true;
  var kr = pg._activeRow, k1 = pg._getColumnOrder('stt_rec'), k2 = pg._getColumnOrder('ngay_ct'), k3 = pg._getColumnOrder('so_ct'), k4 = pg._getColumnOrder('t_tt_nt'), k5 = pg._getColumnOrder('ma_nt'), k6 = pg._getColumnOrder('ty_gia'), k7 = pg._getColumnOrder('tk'), k9 = pg._getColumnOrder('ma_kh');
  var v1 = pg._getItemValue(kr, k1), v2 = pg._getItemValue(kr, k2), v3 = pg._getItemValue(kr, k3), v4 = pg._getItemValue(kr, k4), v5 = pg._getItemValue(kr, k5), v6 = pg._getItemValue(kr, k6), v7 = pg._getItemValue(kr, k7), v9 = pg._getItemValue(kr, k9);
  var l0 = g._getColumnOrder('so_phieu');

  for(var i = 0; i < a.length; i++) {
    var ins = true, row = g._rowCount, d = a[i];
    if (first && row > 0) if (g.blankMemvar(row)) {ins = false; first = false;}
    if (ins) g._appendRow(null, true);
    row = g._rowCount;

    var o = g._getItem(row, l0);
    o.row = row;
    g.setItemGridBehavior(o, [
        ['tag', (f._action == 'New' ? (d[7] != 0 ? true : false) : false), null, false],
        ['stt_rec_phieu', v1, null, false],
        ['ngay_phieu', v2, null, false],
        ['so_phieu', v3, null, false],
        ['tien_nt', v4, null, false],
        ['ma_nt', v5, null, false],
        ['ty_gia', v6, null, false],
        ['tk', v7, null, false],
        ['tien_cl_nt', d[14], null, false],
        ['ma_kh_phieu', v9, null, false],

        ['stt_rec_hd', d[1], null, false],
        ['ngay_hd', d[2], null, false],
        ['so_hd', d[3], null, false],
        ['tien_hd_nt', d[11], null, false],
        ['da_tt_nt', d[12], null, false],
        ['cl_nt', d[13], null, false],
        ['tk_du', d[6], null, false],
        ['tt_nt', d[7], null, false],
        ['tt_qd', d[9], null, false],
        ['ma_nt_hd', d[4], null, false],
        ['ty_gia_hd', d[5], null, false],
        ['tt', d[8], null, false],
        ['tt_nt0', 0, null, false],
        ['ma_kh_hd', d[10], null, false]
      ]);
  }
}
/* </flatten> */
      &DowloadScript;
